For boundary testing in your scoring system, the key MSTest assertions are:

| Scenario | Assertion |
|---|---|
| Exact boundary values (90 → "A") | `Assert.AreEqual(expected, actual)` |
| Score within valid range | `Assert.IsInRange(actual, low, high)` |
| Score above/below threshold | `Assert.IsGreaterThan` / `Assert.IsLessThan` |
| Invalid input throws | `Assert.ThrowsExactly<T>(() => ...)` |

Here's a complete test class:

```csharp
using Contoso.Scoring;

[TestClass]
public sealed class ScoreCalculatorTests
{
    private readonly ScoreCalculator _calculator;

    public ScoreCalculatorTests()
    {
        _calculator = new ScoreCalculator();
    }

    // --- CalculatePercentage ---

    [TestMethod]
    [DataRow(10, 10, 100.0, DisplayName = "Perfect score")]
    [DataRow(0, 10, 0.0, DisplayName = "Zero correct")]
    [DataRow(5, 10, 50.0, DisplayName = "Half correct")]
    [DataRow(1, 3, 33.333333333333336, DisplayName = "Repeating decimal")]
    public void CalculatePercentage_ValidInputs_ReturnsExpected(
        int correct, int total, double expected)
    {
        var result = _calculator.CalculatePercentage(correct, total);
        Assert.AreEqual(expected, result);
    }

    [TestMethod]
    public void CalculatePercentage_ResultAlwaysInRange()
    {
        var result = _calculator.CalculatePercentage(7, 10);
        Assert.IsInRange(result, 0.0, 100.0);
    }

    [TestMethod]
    public void CalculatePercentage_ZeroTotal_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculatePercentage(0, 0));
    }

    [TestMethod]
    public void CalculatePercentage_NegativeTotal_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculatePercentage(0, -1));
    }

    [TestMethod]
    public void CalculatePercentage_NegativeCorrect_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculatePercentage(-1, 10));
    }

    [TestMethod]
    public void CalculatePercentage_CorrectExceedsTotal_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculatePercentage(11, 10));
    }

    // --- GetGrade boundary tests ---

    [TestMethod]
    [DataRow(90.0, "A", DisplayName = "Exact A boundary")]
    [DataRow(80.0, "B", DisplayName = "Exact B boundary")]
    [DataRow(70.0, "C", DisplayName = "Exact C boundary")]
    [DataRow(60.0, "D", DisplayName = "Exact D boundary")]
    public void GetGrade_ExactBoundary_ReturnsHigherGrade(
        double percentage, string expected)
    {
        Assert.AreEqual(expected, _calculator.GetGrade(percentage));
    }

    [TestMethod]
    [DataRow(89.999, "B", DisplayName = "Just below A")]
    [DataRow(79.999, "C", DisplayName = "Just below B")]
    [DataRow(69.999, "D", DisplayName = "Just below C")]
    [DataRow(59.999, "F", DisplayName = "Just below D")]
    public void GetGrade_JustBelowBoundary_ReturnsLowerGrade(
        double percentage, string expected)
    {
        Assert.AreEqual(expected, _calculator.GetGrade(percentage));
    }

    [TestMethod]
    public void GetGrade_PerfectScore_ReturnsA()
    {
        Assert.AreEqual("A", _calculator.GetGrade(100.0));
    }

    [TestMethod]
    public void GetGrade_ZeroScore_ReturnsF()
    {
        Assert.AreEqual("F", _calculator.GetGrade(0.0));
    }

    // --- NormalizeScore ---

    [TestMethod]
    public void NormalizeScore_HalfOfMax_Returns50()
    {
        Assert.AreEqual(50.0, _calculator.NormalizeScore(25.0, 50.0));
    }

    [TestMethod]
    public void NormalizeScore_ExceedsMax_CapsAt100()
    {
        var result = _calculator.NormalizeScore(120.0, 100.0);
        Assert.AreEqual(100.0, result);
    }

    [TestMethod]
    public void NormalizeScore_ResultNeverExceeds100()
    {
        var result = _calculator.NormalizeScore(999.0, 10.0);
        Assert.IsLessThan(101.0, result);
    }

    [TestMethod]
    public void NormalizeScore_ValidInput_ResultNotNegative()
    {
        var result = _calculator.NormalizeScore(0.0, 50.0);
        Assert.IsGreaterThan(-1.0, result);
    }

    [TestMethod]
    public void NormalizeScore_NegativeRawScore_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.NormalizeScore(-1.0, 100.0));
    }

    [TestMethod]
    public void NormalizeScore_ZeroMaxRaw_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.NormalizeScore(50.0, 0.0));
    }

    [TestMethod]
    public void NormalizeScore_NegativeMaxRaw_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.NormalizeScore(50.0, -10.0));
    }
}
```

**Key patterns used:**

- **`Assert.IsInRange(actual, low, high)`** — verifies a score stays within `[0, 100]`
- **`Assert.IsGreaterThan` / `Assert.IsLessThan`** — one-sided boundary checks
- **`Assert.ThrowsExactly<T>`** — validates guard clauses reject invalid inputs
- **`Assert.AreEqual(expected, actual)`** — exact boundary values (e.g., 90.0 → "A" vs 89.999 → "B")
- **`[DataRow]` with `DisplayName`** — parameterized tests at each grade boundary, testing both sides

The boundary strategy: test the **exact threshold** (gets higher grade) and **just below** (gets lower grade) to confirm the `>=` comparisons in `GetGrade` are correct.
